const Q_GEOGRAPHY_2009=[{"id": "objective>Geography>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The location of Sabe town has been influenced mostly by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mineral workings and agriculture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rivers that pass through the town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latitude of the area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral workings and transportation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The good transport network (rail & road) supported the mining sector to help in founding of sale settlement on the map.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total length of river Yalen from the boundary at Ijer to its confluence with river Ayila is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.8km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.6km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.7km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.3km</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">River Yalen from Ijer to river Ayila as traced with white thread & measured on a metre rule = 5.7cm  <br/>  but scale = 1:100000  <br/>  = 1:1Km  <br/>  = 5.7km</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The elevation of the point marked <strong>Z</strong> is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">525m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">550m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">575m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Height is measured from contour lines  <br/>  → trace the last labelled contour height and count based on change in height by number of contour = 525m </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The landform marked <strong>S</strong> is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">col</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Knoll</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Knolls are small highland round in nature and forming a pass gap with a neighbouring higher highland feature.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following crops are likely to do well in the south west?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cocoa and cassava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maize and cocoa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rice and sugarcane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sugarcane and coffee</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rice and sugarcane are best suited for cultivation in marshlands. </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference between communication and transportation is that transportation </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">involves physical carriage of things while communication involves transmission of information</div>", "<div style=\"font-family:Cambria;font-size:17px;\">requires good infrastructure on the ground while communication requires a system of satellites in space</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is land-based while communication is air - borne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">involves the use of vehicles while communication involves the use of cables</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transportation involves physical carriage of things while communication involves transmission of information.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Many important ancient settlements in the Middle East developed as a result of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trans-Saharan slave trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">existence of oases in the deserts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of large quantities of crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emergence of important trading routes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Many important ancient settlements in the Middle East developed as a result of the existence of oases in the deserts.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Proportional circles are commonly used to illustrate the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">information on transport</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative amount of traffic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amount of rainfall</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Proportional circles are commonly used to show differentials in size and distribution of populated settlements.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Open traverse method is not suitable for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boundary lines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rugged terrains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steep slopes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marshy areas</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marshy land don't support for accurate results using open transverse method in survey. Open transverse will not because the terrain will not allow for setting controls.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rotation of the earth on its own axis results in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the four seasons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">varying lengths of day and night at different times of the year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes in the altitude of the midday sun at different times of the year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">day and night</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rotation of the earth around its own axis results in day & night. All other option are as a result of revolution not rotation.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the time in New York (75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>W) is 5.00pm, the time in Nigeria (15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>E) will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11:00am</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11:00pm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9:00pm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9:00am</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> But 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 1hr  <br/> ∴ 75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = x  <br/>  x = 75/15 = 5hrs  <br/>  time in EM in England = 12pm  <br/>  Nigerian time = New York time - (Sum of hours difference)  <br/>  = 5pm - (5 + 1)  <br/>  = 5pm - 6hr  <br/>  = 11pm.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hard, shiny and carbon-rich organic rock that burns smokelessly is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">peat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhyolite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marble</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anthracite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anthracite is a hard, shiny, and carbon-rich organic rock that burns smokelessly. It is the highest rank of coal and contains the highest carbon content, between 86% and 98%. This makes it the cleanest burning coal, and it gives off a lot of heat when it burns. Peat, rhyolite, and marble are not carbon-rich organic rocks that burn smokelessly.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Limestone and clay metamorphosed into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marble and gneiss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marble and slate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite and quartzite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite and gypsum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Limestone and clay metamorphosis under adequate pressure and heat overtone to give marble and slate.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The process of landform development illustrated is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">folding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">volcanic eruption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faulting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass movement</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Faulting occurs when new highland features are created as a result of movement along the faults.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The slope labelled <strong>X</strong> is best described as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">valley-side slope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">faultscarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cuesta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fault-line scarp</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fault-line scarp results from faulting. The slope labelled <strong>X</strong> is best described as a valley-side slope </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The portion of the land which rises higher than other areas is described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a volcanic cone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an anticline hill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an escarpment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a block mountain</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A block mountain or a horst is a portion of the land that rises higher than other areas due to geological activities. It is formed by the movement of large crustal blocks when forces in the Earth's crust cause it to break apart. It is not necessarily a volcanic cone, an anticline hill, or an escarpment. Therefore, the correct answer is 'a block mountain'.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A seif is a landform associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">river deposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marine erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind deposition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seif dunes in deserts results from dolian/wind deposition of sand to form spectacular ridge-like features. </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a product of volcanicity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plug dome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ocean trench</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fold mountain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rift valley lake</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plugdome: is a characteristic feature of an extinct basaltic volcanic region where magma has cooled down the major vent of the volcano to form a dome.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The largest ocean in the world is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Atlantic Ocean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Indian Ocean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arctic Ocean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pacific Ocean</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The atlantic ocean is the largest ocean in the world bordering Europe, Africa, North and South America and the caribbeans.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The classification of clouds is based on a combination of form, height and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">colour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">width</div>", "<div style=\"font-family:Cambria;font-size:17px;\">movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appearance</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Having classified clouds by form and height the last major distinguishing feature of note is the appearance fluffy, plumes etc.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hygrometer is used to measure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sunshine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hygrometer is an instrument used to measure the amount of humidity and water vapor in the atmosphere, in soil, or in confined spaces. Humidity measurement in meteorology is of great importance as it affects both weather and climate. Therefore, the correct answer is 'relative humidity'.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at which condensation occurs when air is saturated is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">freezing point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dew point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">atmospheric point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at which the water vapor in the air becomes saturated and condensation begins is called the dew point. It is the temperature at which air becomes saturated, causing the formation of dew droplets. Therefore, the correct answer is 'dew point'.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Spruce, pine and fir are trees associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Savanna grassland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coniferous forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean woodland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical evergreen forest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spruce, for and pines are softwood trees found in temperate coniferous forests used in pulp & paper industry.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main process of soil formation in humid tropics is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">podzolization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">laterization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wet & dry seasons encourage laterization (formation of laterite) in humid tropics. This is aided by the peculiar vegetation cover formed here a source of organic matter.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soils that are greatly influenced by the parent material in the process of their formation are referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mineral soils </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zonal soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intra-zonal soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">azonal soils</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intrazonal soils have a well defined soil profile characteristics reflecting the dominant influence of some relier factors or parent material.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sources of power supply is renewable?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Solar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solar power is a renewable source of energy. It is derived from the sun's radiation and can be converted into electricity or heat. Unlike fossil fuels such as coal and gas, solar power does not deplete natural resources or cause environmental pollution.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most critical element in an ecosystem is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of species within the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">area covered by the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy flow within the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of growth of species within the system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Energy flow determines survival, nutrient & energy transfer from one trophic level to the other as well as primary food production by micro-organisms and plants.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Flooding in coastal areas can best be checked by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">terracing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tree planting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">channelization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contour ploughing</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Channelization is the artificial method of forcing water to flow within a restricted pathway constructed.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major geographical factors that determine the pattern of population distribution include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vegetation, soil, health care and climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">climate, vegetation, relief and accessibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relief, minerals, accessibility and communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agriculture, soil, climate and minerals</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture, soil, climate and minerals have since the origin of man till date been major influences on settlement formation as well as pattern development & population growth.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population pyramid for a developed country has a narrow base which indicates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high birth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more females than males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high fertility ratio</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A population pyramid for a developed country typically has a narrow base, which indicates a low birth rate. This is because developed countries often have lower fertility rates due to factors such as better access to contraception, higher levels of education, and the high cost of raising children.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the birth rate of a country with a total population of 160million and registered births of 4 million in a given year?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.00%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Birth</td><td style=\"text-align:center;\">rate</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">number of live births<hr size=\"1\" />total population</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4 million<hr size=\"1\" />160 million</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />40</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div>  <br/>  = 2.55 per annum.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Detroit in the U.S.A. came into prominence as a result of its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">automobile industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">administrative functions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial functions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">military function</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Detroit in the U.S.A. came into prominence as a result of its automobile industries. It is famously known as the birthplace of the American automobile industry and was once home to the headquarters of General Motors, Ford, and Chrysler.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following explains the importance of the concept of site and situation of settlements?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both site and situation are most favourable for the establishment and growth of settlements.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All site and situations are located on plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both site and situation are not favourable to the establishment and growth of settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All settlements are located on site and situation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a settlement to be founded at a particular location, then, its site and situation must favour and be able to support a settlement as of that time.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The world's busiest seaport is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kobe </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rotterdam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bombay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">London</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The world's busiest seaport is Rotterdam. This is based on the volume of cargo handled. Rotterdam is strategically located and has excellent infrastructure, making it a major hub for international trade.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization mostly helps developing countries to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diversify their economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acquire greatness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">put their resources together </div>", "<div style=\"font-family:Cambria;font-size:17px;\">develop infrastructure</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic diversification is a direct impact of industrialization for developing countries as activities more from primary to secondary & tertiary economic activities dominating EDP.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major physical factor restricting the cultivation of perennial crops in the sudan savanna of Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seasonal regime of the streams</div>", "<div style=\"font-family:Cambria;font-size:17px;\">menace of pests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonal pattern of rainfall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandy nature of the soil</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sudan savanna in Nigeria is semi-desert in nature with little rainfall sparsely over few months in a year.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major primary activity in a coniferous forest is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">paper manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hunting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">furniture making</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paper manufacturing exploits the softwood resources found in temperate coniferous forests.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The state in Nigeria most vulnerable to drought and desertification is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kaduna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yobe</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yobe state in Nigeria is most vulnerable to drought and desertification. This is due to its location in the Sahel region, which is characterized by low rainfall and high temperatures. The other states listed are not as vulnerable to drought and desertification as Yobe.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important use of rocks in Nigeria is for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revenue generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">building </div>", "<div style=\"font-family:Cambria;font-size:17px;\">export</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tourism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mining licenses and other royalties are sources of income from rock mining/quarrying.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The low level of economic development in the Chad Basin of Nigeria is owing to its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rugged topography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overpopulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harsh climate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The harsh semi-desert climate of the chad Basin of Nigeria could be responsible for the low level of economic development there.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Enugu-Nsukka plateau in Nigeria is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volcanic plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissected plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tectonic plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermontane plateau</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The disection of the Enugu-Nsukka plateau of South Eastern Nigeria has led to the famous escarpment in the region.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first railway line that was built in Nigeria was from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lagos to Kano</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos to Maiduguri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zaria to Kaura Namoda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna to Jos</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos to Kano railway line was the first in Nigeria linking the 2 largest commercial cities of the nation together.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best way to promote industrialization in Nigeria is through the development of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron and steel processing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">automobile manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">textile manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cassava processing</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iron & Steel are the foundation for industrialization as most factory's machineries & plants are made with them.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The craft industry with the late Ladi Kwali in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weaving</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pottery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carving</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dyeing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ladi Kwali was a famous Nigerian potter who was known for her skills in pottery. She was awarded the Nigerian National Merit Award for her contributions to the development of pottery in Nigeria. Therefore, the craft industry associated with Ladi Kwali in Nigeria is pottery.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An area in Shaba province in the Democratic Republic of Congo known for the production of copper is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ndola </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nchanga</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lubumbashi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chibuluma</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lubumbashi is a city in the southeastern part of the Democratic Republic of Congo, which is known for its copper production. It is located in the Shaba (now Katanga) province, which is rich in mineral resources, especially copper.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country in Africa with little or no potential for hydroelectricity generation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mozambique</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania is a desert country in North-Western Africa lacking rivers dropping overheight a scenarios for HEP exploitation.</div>", "topic": "REGIONAL GEOGRAPHY : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a man-made lake is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lake Tanganyika</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake Volta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake Victoria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake Chad</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lake Volta is an example of a man-made lake. It was created by the construction of the Akosombo Dam on the Volta River in Ghana. Man-made lakes, also known as reservoirs, are usually formed by damming rivers to store water for various uses such as hydroelectric power generation, irrigation, and water supply.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following systems provides both irrigation water and hydro-electricity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gezira</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aswan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shiroro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volta</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Aswan High Dam in Egypt provides both irrigation water and hydro-electricity. The dam controls the flow of the Nile River, providing water for irrigation and generating hydroelectric power.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An African city located within the Mediterranean climatic zone is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dakar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addis Ababa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cape Town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mombasa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cape Town in South Africa has similar characteristics to the Mediterranean Climatic zone also found in North Africa region from Morocco to Tunisia coastal lands.</div>", "topic": "REGIONAL GEOGRAPHY : FRUIT FARMING IN THE MEDITERRANEAN REGIONS OF AFRICA."}, {"id": "objective>Geography>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main factor that is responsible for the relatively cool temperatures in East Africa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ocean current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Latitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Air mass</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Altitude or high relief as a result of the highlands forming the Rift Valley system create a relatively cold temperature region in East Africa.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}];
